#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
const ll mod=998244353;
ll n,m,a[N],anss[N],cnt;
inline ll read()
{
	ll x=0,f=1;
	char ch=getchar();
	while(ch<'0'||ch>'9')
	{
		if(ch=='-') f=mod-1;
		ch=getchar();
	}
	while(ch>='0'&&ch<='9')
	{
		x=x*10+(ch-'0');
		x%=mod;
		ch=getchar();
	}
	return (x*f)%mod;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("P2312_6.in","r",stdin);
//	freopen(".out","w",stdout);
	n=read();
	m=read();
	for(int i=0;i<=n;i++) a[i]=read();
	for(int i=1;i<=m;i++)
	{
		ll ans=a[n];
		for(int j=1;j<=n;j++)
		{
			ans=(ans*i+a[n-j])%mod;
		}
		if(ans==0) anss[++cnt]=i;
	}
	cout<<cnt<<"\n";
	for(int i=1;i<=cnt;i++)
	{
		cout<<anss[i]<<'\n';
	}
	return 0;
}
